import { useEffect, useState } from 'react';
import { Mic, MicOff, Volume2 } from 'lucide-react';

export function AudioSpeechVisualizer() {
  const [state, setState] = useState("thinking"); // listening, thinking, speaking, muted
  const [bars, setBars] = useState(Array(15).fill(20));

  useEffect(() => {
    if (state === "muted") {
      setBars(Array(15).fill(4));
      return;
    }

    const interval = setInterval(() => {
      setBars((prev) => 
        prev.map(() => {
          if (state === "thinking") {
            // Slow pulsing waves
            return Math.sin(Date.now() / 200) * 10 + 20;
          }
          // Active dynamic speech waves
          return Math.random() * 40 + 8;
        })
      );
    }, 100);

    return () => clearInterval(interval);
  }, [state]);

  return (
    <div className="w-full max-w-sm mx-auto border border-border bg-[#09090b] text-white p-6 rounded-2xl shadow-xl flex flex-col items-center justify-between">
      {/* Agent Voice Status Header */}
      <div className="flex items-center justify-between w-full mb-6">
        <div className="flex items-center gap-2">
          <span className={`h-2.5 w-2.5 rounded-full ${state === 'listening' ? 'bg-emerald-500 animate-ping' : 'bg-primary'}`} />
          <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent Voice Session</span>
        </div>
        <span className="text-xs text-neutral-400 capitalize">{state}</span>
      </div>

      {/* Animated Waveform Bars */}
      <div className="flex items-center justify-center gap-1.5 h-32 w-full mb-8">
        {bars.map((height, i) => (
          <span 
            key={i}
            style={{ height: `${height}px` }}
            className={`w-1 rounded-full transition-all duration-100 ${
              state === "muted"
                ? 'bg-neutral-800'
                : state === "speaking"
                ? 'bg-[#00adb5]'
                : 'bg-primary/60'
            }`}
          />
        ))}
      </div>

      {/* Interactive Controls */}
      <div className="flex items-center justify-center gap-4 border-t border-white/5 pt-6 w-full">
        <button 
          onClick={() => setState(state === "muted" ? "listening" : "muted")}
          className={`p-3 rounded-full border transition-all ${state === "muted" ? 'bg-rose-500/20 border-rose-500 text-rose-500' : 'bg-neutral-900 border-white/10 hover:bg-neutral-800 text-muted-foreground'}`}
        >
          {state === "muted" ? <MicOff className="h-5 w-5" /> : <Mic className="h-5 w-5" />}
        </button>

        <button 
          onClick={() => setState(state === "speaking" ? "listening" : "speaking")}
          className={`px-5 py-2.5 rounded-xl border text-xs font-bold transition-all border-white/10 bg-neutral-900 hover:bg-neutral-800 flex items-center gap-2 text-white`}
        >
          <Volume2 className="h-4 w-4 text-primary" />
          <span>Simulate Reply</span>
        </button>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Type } from 'lucide-react';

export function FontsharePlayground() {
  const [text, setText] = useState("Beautiful typography empowers visual design stories.");
  const [fontSize, setFontSize] = useState(24);
  const [fontWeight, setFontWeight] = useState(400);
  const [fontFamily, setFontFamily] = useState("sans-serif");

  return (
    <div className="w-full max-w-xl mx-auto border border-border bg-card text-card-foreground p-6 rounded-2xl shadow-xl space-y-6">
      {/* Controls Bar */}
      <div className="grid grid-cols-3 gap-4 border-b border-border pb-6">
        <div>
          <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Font Family</label>
          <select 
            value={fontFamily}
            onChange={(e) => setFontFamily(e.target.value)}
            className="w-full mt-1.5 p-2 bg-muted border border-border rounded-xl text-xs focus:outline-none text-foreground"
          >
            <option value="sans-serif">System Sans</option>
            <option value="serif">System Serif</option>
            <option value="monospace">System Monospace</option>
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Size ({fontSize}px)</label>
          <input 
            type="range" 
            min="16" 
            max="64" 
            value={fontSize} 
            onChange={(e) => setFontSize(Number(e.target.value))}
            className="w-full mt-3 accent-primary cursor-pointer"
          />
        </div>

        <div>
          <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Weight ({fontWeight})</label>
          <input 
            type="range" 
            min="300" 
            max="900" 
            step="100" 
            value={fontWeight} 
            onChange={(e) => setFontWeight(Number(e.target.value))}
            className="w-full mt-3 accent-primary cursor-pointer"
          />
        </div>
      </div>

      {/* Text Tester Area */}
      <div className="relative border border-border/80 bg-muted/20 p-6 rounded-xl min-h-[140px] flex items-center justify-center">
        <textarea 
          value={text}
          onChange={(e) => setText(e.target.value)}
          style={{
            fontSize: `${fontSize}px`,
            fontWeight: fontWeight,
            fontFamily: fontFamily
          }}
          className="w-full bg-transparent resize-none border-none focus:outline-none text-center text-foreground"
        />
        <div className="absolute bottom-3 right-3 flex items-center gap-1 text-[10px] text-muted-foreground">
          <Type className="h-3.5 w-3.5" />
          <span>Fontshare Sandbox</span>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { BookOpen, ChevronLeft, ChevronRight, RefreshCw } from 'lucide-react';

export function MangaViewer() {
  const [currentPage, setCurrentPage] = useState(1);
  const [isRTL, setIsRTL] = useState(true);
  const totalPages = 8;

  const nextPage = () => {
    setCurrentPage((prev) => (isRTL ? Math.max(1, prev - 1) : Math.min(totalPages, prev + 1)));
  };

  const prevPage = () => {
    setCurrentPage((prev) => (isRTL ? Math.min(totalPages, prev + 1) : Math.max(1, prev - 1)));
  };

  return (
    <div className="w-full max-w-lg mx-auto border border-border bg-neutral-900 text-white rounded-2xl overflow-hidden shadow-2xl p-4">
      {/* Viewer Header Options */}
      <div className="flex items-center justify-between border-b border-white/5 pb-3 mb-4">
        <div className="flex items-center gap-2">
          <BookOpen className="h-5 w-5 text-primary" />
          <span className="text-xs font-semibold">Comimi Manga Sandbox</span>
        </div>

        <button 
          onClick={() => setIsRTL(!isRTL)}
          className="flex items-center gap-1.5 px-3 py-1 bg-white/5 hover:bg-white/10 rounded-lg text-xs transition-all"
        >
          <RefreshCw className="h-3.5 w-3.5 text-primary" />
          <span>{isRTL ? "RTL (Right to Left)" : "LTR (Left to Right)"}</span>
        </button>
      </div>

      {/* Comic Page Viewport Panels */}
      <div className="relative aspect-[4/3] bg-neutral-950 rounded-xl overflow-hidden flex items-center justify-center border border-white/5">
        <div className="grid grid-cols-2 h-full w-full p-6 gap-3">
          {/* Page Panel Left */}
          <div className="bg-neutral-800/40 border border-white/10 rounded-lg flex items-center justify-center text-center p-4">
            <div>
              <span className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider">Page</span>
              <h3 className="text-3xl font-extrabold text-white mt-1">{currentPage}</h3>
            </div>
          </div>
          {/* Page Panel Right */}
          <div className="bg-neutral-800/40 border border-white/10 rounded-lg flex items-center justify-center text-center p-4">
            <div>
              <span className="text-[10px] text-muted-foreground uppercase font-bold tracking-wider">Page</span>
              <h3 className="text-3xl font-extrabold text-white mt-1">{currentPage + 1 <= totalPages ? currentPage + 1 : "End"}</h3>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation Controls footer */}
      <div className="flex items-center justify-between mt-4">
        <button 
          onClick={prevPage}
          className="p-2 bg-white/5 hover:bg-white/10 rounded-xl transition-all text-white border border-white/10"
        >
          <ChevronLeft className="h-5 w-5" />
        </button>

        <span className="text-xs text-neutral-400 font-mono">Spread {currentPage} - {currentPage + 1 <= totalPages ? currentPage + 1 : totalPages} of {totalPages}</span>

        <button 
          onClick={nextPage}
          className="p-2 bg-white/5 hover:bg-white/10 rounded-xl transition-all text-white border border-white/10"
        >
          <ChevronRight className="h-5 w-5" />
        </button>
      </div>
    </div>
  );
}
